class Solution:
    def canMakeSubsequence(self, str1: str, str2: str) -> bool:
        str1_count = [0] * 26
        str2_count = [0] * 26
        for char in str1:
            str1_count[ord(char) - ord('a')] += 1
        for char in str2:
            str2_count[ord(char) - ord('a')] += 1
        for i in range(26):
            if str1_count[i] < str2_count[i]:
                return False
        return True
